Here's how to test `DataFetcher` with modern MSTest 3.x/4.x, covering success, failure, cancellation, and timeouts:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode status = HttpStatusCode.OK,
        string content = "")
    {
        var handler = new FakeHandler(status, content);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var (fetcher, _) = CreateFetcher(HttpStatusCode.OK, "hello world");

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays long enough for cancellation to fire
        using var cts = new CancellationTokenSource();
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Cancel immediately
        cts.Cancel();

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // test itself fails if it takes > 5s
    public async Task FetchAsync_WithTimeout_CompletesInTime()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.OK, "fast");

        // Pass TestContext.CancellationToken so [Timeout] can cancel the call
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    [Timeout(1000)]
    public async Task FetchAsync_SlowResponse_TimeoutCancelsOperation()
    {
        // Arrange — handler that never responds within the timeout
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert — [Timeout] triggers CancellationToken after 1s
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    // --- Test doubles ------------------------------------------------

    private sealed class FakeHandler(HttpStatusCode status, string content)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
            return Task.FromResult(response);
        }
    }

    private sealed class DelayHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken); // throws when cancelled
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `TestContext.CancellationToken` | Hooks into `[Timeout]` — the framework cancels the token when time expires |
| `[Timeout(ms)]` + `CancellationToken` | Cooperative timeout — test fails cleanly instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type (not a subclass) |
| `FakeHandler` / `DelayHandler` | Subclass `HttpMessageHandler` to control `HttpClient` without a mocking library |
| Sealed test class + constructor injection | Modern MSTest best practice for performance and `TestContext` access |

The critical insight: **`[Timeout]` alone won't cancel your async code** — you must pass `TestContext.CancellationToken` into every awaited call so the framework can cooperatively cancel the operation when the timeout fires.
